import React from 'react';
import { Swiper, SwiperSlide } from 'swiper/react';
import { Navigation, Pagination, Autoplay, EffectCoverflow } from 'swiper/modules';

// Swiper stillerini içe aktar
import 'swiper/css';
import 'swiper/css/navigation';
import 'swiper/css/pagination';
import 'swiper/css/effect-coverflow';
import '../../styles/Slider.css'; // Kendi özel stillerinizi ekleyin

const slides = [
  {
    id: 1,
    title: "Geleceği Keşfedin",
    desc: "Yapay zeka ve modern teknolojilerle tanışın.",
    img: "https://images.unsplash.com/photo-1635070041078-e363dbe005cb?q=80&w=1000",
  },
  {
    id: 2,
    title: "Yaratıcı Tasarımlar",
    desc: "Estetik ve fonksiyonelliği bir araya getiren çözümler.",
    img: "https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?q=80&w=1000",
  },
  {
    id: 3,
    title: "Hızlı Performans",
    desc: "React ile optimize edilmiş akıcı arayüz deneyimi.",
    img: "https://images.unsplash.com/photo-1550745165-9bc0b252726f?q=80&w=1000",
  }
];

const ModernSlider = () => {
  return (
    <div className="slider-container">
      <Swiper
        effect={'coverflow'}
        grabCursor={true}
        centeredSlides={true}
        slidesPerView={'auto'}
        coverflowEffect={{
          rotate: 50,
          stretch: 0,
          depth: 100,
          modifier: 1,
          slideShadows: true,
        }}
        autoplay={{
          delay: 3000,
          disableOnInteraction: false,
        }}
        pagination={{ clickable: true }}
        navigation={true}
        modules={[EffectCoverflow, Pagination, Navigation, Autoplay]}
        className="mySwiper"
      >
        {slides.map((slide) => (
          <SwiperSlide key={slide.id}>
            <div className="card">
              <img src={slide.img} alt={slide.title} />
              <div className="card-content">
                <h2>{slide.title}</h2>
                <p>{slide.desc}</p>
                <button className="cta-btn">Daha Fazla</button>
              </div>
            </div>
          </SwiperSlide>
        ))}
      </Swiper>
    </div>
  );
};

export default ModernSlider;
